function letters(prompt1, prompt2) {
    const isLetter = (str) => typeof str === 'string' && /^[a-zA-Zа-яА-ЯёЁ]$/.test(str);
    if (!isLetter(prompt1) || !isLetter(prompt2)) {
        return -1;
    }
    if (prompt1 === prompt1.toUpperCase() && prompt2 === prompt2.toUpperCase()) {
        return 1;
    } else {
        return 0;
    }
}

