function powers(n) {
    let arr = [];
    while (n > 0) {
        let e = Math.floor(Math.log2(n));
        arr.push(Math.pow(2, e));
        n = n - 2**e;
    }
    arr.sort((a, b) => a - b);
    return arr;
}

