console.log(result);

function calc(arg1, sym, arg2) {
    if (!"+-*/".includes(sym)) {
        return null;
    }
    if (sym === "/" && arg2 === 0) {
        return null;
    }

    switch (sym) {
        case '+':
            return arg1 + arg2;
        case '-':
            return arg1 - arg2;
        case '*':
            return arg1 * arg2;
        case '/':
            return arg1 / arg2;
    }
}

