console.log(calc(1, "*", 3));
console.log(calc(1, "/", 3));
console.log(calc(1, "/", 0));
console.log(calc(1, "%", 3));

function strLenght(smth) {
    if (smth.length % 2 === 0) {
        let sym1 = smth[smth.length / 2 - 1];
        let sym2 = smth[smth.length / 2];
        return sym1 + sym2;
    } else {
        let sym1 = smth[Math.floor(smth.length / 2)];
        return sym1;
    }
}

console.log(strLenght("Bebra"));
console.log(strLenght("Pivo"));
